console.log("[code.ts] Starting plugin (step 7 - final)...");

figma.showUI(__html__, { width: 432, height: 720 });

console.log("[code.ts] Plugin started (step 7 - final)");

// 当前语言，默认为英文
let currentLang = "en";

// 语言配置
const i18n = {
  en: {
    selectImageNode: "Please select an image node first",
    selectOnlyOneImage: "Please select only one image node",
    invalidImageNode: "Selected node is not a valid image node",
    errorProcessing: "Error processing image"
  },
  zh: {
    selectImageNode: "请先选择一个图片节点",
    selectOnlyOneImage: "请只选择一个图片节点",
    invalidImageNode: "所选节点不是有效的图片节点",
    errorProcessing: "处理图片时出错"
  }
};

// 翻译函数
function t(key: string): string {
  return i18n[currentLang as keyof typeof i18n][key as keyof typeof i18n.en] || key;
}

async function checkAndSendSelection() {
  const selection = figma.currentPage.selection;
  console.log("[code.ts] checkAndSendSelection, current selection:", selection);
  let response: { type: string; data?: any; error?: string } = {
    type: "selection-checked"
  };
  try {
    if (selection.length === 0) {
      response.error = t("selectImageNode");
    } else if (selection.length > 1) {
      response.error = t("selectOnlyOneImage");
    } else {
      const node = selection[0];
      console.log("[code.ts] Selected node:", node);
      console.log("[code.ts] Node type:", node.type);
      
      if (!("width" in node) || !("height" in node)) {
        response.error = t("invalidImageNode");
      } else {
        console.log("[code.ts] Using node.exportAsync() to get image...");
        const imageBytes = await node.exportAsync({ format: "PNG" });
        console.log("[code.ts] Got image bytes from exportAsync, length:", imageBytes.length);
        
        const byteArray = Array.from(imageBytes);
        
        response.data = {
          nodeId: node.id,
          nodeName: node.name,
          width: node.width,
          height: node.height,
          imageBytes: byteArray
        };
      }
    }
  } catch (error) {
    console.error("[code.ts] Error in checkAndSendSelection:", error);
    response.error = `${t("errorProcessing")}: ${(error as Error).message}`;
  }
  console.log("[code.ts] Sending response to UI:", response);
  figma.ui.postMessage(response);
}

figma.ui.onmessage = async (msg) => {
  console.log("[code.ts] Received message from UI:", msg);
  if (msg.type === "ui-ready") {
    await checkAndSendSelection();
  } else if (msg.type === "change-language") {
    currentLang = msg.lang || "en";
    console.log("[code.ts] Language changed to:", currentLang);
    await checkAndSendSelection();
  }
};

figma.on("selectionchange", async () => {
  console.log("[code.ts] selectionchange triggered");
  await checkAndSendSelection();
});
